// Valideert de aanvraag en voegt een net maillabel toe per calculator-id.
// NIEUWE CALCULATOR OP DE SITE? Voeg hier één regel toe aan LABELS.
// Onbekende id's worden NIET geweigerd (val terug op generiek label),
// zodat een vergeten regel nooit leads kost.
const b = $input.first().json.body || {};

const LABELS = {
  'pretest': 'de pretest',
  'effectmeting': 'het campagne-effectonderzoek',
  'customer-journey': 'het customer journey onderzoek',
  'klanttevredenheid': 'het klanttevredenheidsonderzoek',
  'diepte-interviews': 'de diepte-interviews',
  'groepsdiscussie': 'de groepsdiscussie',
  'doelgroeponderzoek': 'het doelgroeponderzoek',
  'kwantitatief-onderzoek': 'het kwantitatief onderzoek',
  'kwalitatief-onderzoek': 'het kwalitatief onderzoek',
  'waardepropositie': 'het waardepropositie-onderzoek',
};

const details = [];
if (!b.naam || !String(b.naam).trim()) details.push('naam ontbreekt');
if (!b.bedrijf || !String(b.bedrijf).trim()) details.push('bedrijfsnaam ontbreekt');
if (!b.email || !/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(String(b.email))) details.push('geldig e-mailadres ontbreekt');
if (b.consent !== true) details.push('AVG-akkoord ontbreekt');

const label = LABELS[b.calculator] || ('de rekenmodule "' + (b.calculator || 'onbekend') + '"');
const bekend = Boolean(LABELS[b.calculator]);
const samenvatting = Array.isArray(b.samenvatting) ? b.samenvatting : [];
const samenvattingTekst = samenvatting.length ? '- ' + samenvatting.join('\n- ') : '—';

return [{
  json: {
    valid: details.length === 0,
    details,
    aanvraag: {
      ...b,
      label,
      bekendeCalculator: bekend,
      samenvattingTekst,
      richtprijsFormatted: b.richtprijsFormatted || 'Op aanvraag',
    },
  },
}];

